SELECT /* UserInfoMgmtMapper.selectUserInfoMgmtList */ CUM.USR_ID /* 사용자 ID */ , CUM.ATTC_SCTN_CD /* 소속 구분 코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = CUM.ATTC_SCTN_CD) as ATTC_SCTN_CD_NM , CUM.USR_NM /* 사용자 명 */ --, CUM.PASS /* 비밀번호 */ , CUM.TEL_NUM /* 전화 번호 */ , CUM.MBLPHN_NUM /* 핸드폰 번호 */ , CUM.LAST_LOGIN_DT /* 최종 로그인 일시 */ , CUM.PASS_ERR_NUM /* 암호 오류 횟수 */ , CUM.PRES_BIZ /* 사번 */ , CUM.EMAIL /* 이메일 */ , CUM.POS /* 직위 */ , CUM.ODTY /* 직책 */ , CUM.ADDR /* 주소 */ , CUM.DTL_ADDR /* 상세 주소 */ , CUM.ZIPCD /* 우편 번호 */ , CUM.FAX /* FAX 번호 */ , CUM.PASS_ATMT_NUM /* 비밀번호 시도 횟수 */ , CUM.DEL_YN /* 삭제 여부 */ , CUM.REGST_ID /* 등록자 ID */ , TO_CHAR(CUM.REGST_DTTM,'YYYY-MM-DD HH:mm:ss') as REGST_DTTM /* 등록 일시 */ , CUM.RVISN_ID /* 수정자 ID */ , FN_GET_USRNM(CUM.RVISN_ID) AS RVISN_NM /* 수정자 */ , CUM.RVISN_DTTM /* 수정일시 */ , CUM.DEPT /* 부서코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = CUM.DEPT) as DEPT_NM , CUM.IP_INFO /* IP정보 */ , CUM.MAC_ADDR /* MAC주소 */ , CUM.USG_YN /* 사용여부 */ , CUM.USG_STRT_DT /* 사용시작일자 */ , CUM.USG_END_DT /* 사용종료일자 */ , CUM.PASS_LAST_RVISN_DT /* 최종비밀번호변경일시 */ , DECODE(CUM.MNGR_RULE, 'Y', 'Y', '1', 'Y', 'N') AS MNGR_RULE /* 관리자롤 */ , DECODE(CUM.MSK_AUTH_YN, 'Y', 'Y', '1', 'Y', 'N') AS MSK_AUTH_YN /* 마스킹권한여부 */ , ORGN_ID , FN_GET_ORGNM(CUM.ORGN_ID) as ORGN_NM , KOS_ID , DECODE(CUM.MAC_CHK_YN, 'Y', 'Y', '1', 'Y', 'N') AS MAC_CHK_YN , DECODE(CUM.USG_YN,'Y','사용','정지') AS USG_NM /* 마스킹 정보 */ , CUM.USR_ID AS USR_ID_MSK , CUM.USR_NM AS USR_NM_MSK , CUM.TEL_NUM AS TEL_NUM_MSK , CUM.MBLPHN_NUM AS MBLPHN_NUM_MSK , CUM.FAX AS FAX_MSK , CUM.EMAIL AS EMAIL_MSK , CUM.KOS_ID AS KOS_ID_MSK , CUM.LOCK_YN FROM CMN_USR_MST CUM WHERE 1=1 AND USG_YN != 'N' --AND ATTC_SCTN_CD != '30'
AND USR_ID LIKE UPPER(#{usrId}||'%')
AND USR_NM LIKE '%'|| UPPER(#{usrNm}) ||'%'
AND USG_YN = #{usgYn}
AND ATTC_SCTN_CD = #{attcSctnCd}
AND DEPT = #{dept}
AND ORGN_ID = #{orgnId}
ORDER BY REGST_DTTM DESC

