	   UPDATE CMN_USR_MST /** UserInfoMgmtMapper.updateUserInfoMgmt */ 
           SET
            USR_NM = #{usrNm, jdbcType=VARCHAR}  
           , ATTC_SCTN_CD = #{attcSctnCd, jdbcType=VARCHAR} 
           , PASS = #{pass, jdbcType=VARCHAR} 
           , TEL_NUM = #{telNum, jdbcType=VARCHAR} 
           , MBLPHN_NUM = #{mblphnNum, jdbcType=VARCHAR} 
           , PRES_BIZ = #{presBiz, jdbcType=VARCHAR} 
           , EMAIL = #{email, jdbcType=VARCHAR} 
           , POS = #{pos, jdbcType=VARCHAR} 
           , ODTY = #{odty, jdbcType=VARCHAR} 
           , ADDR = #{addr, jdbcType=VARCHAR} 
           , DTL_ADDR = #{dtlAddr, jdbcType=VARCHAR} 
           , ZIPCD = #{zipcd, jdbcType=VARCHAR} 
           , FAX = #{fax, jdbcType=VARCHAR} 
           , RVISN_ID = #{rvisnId, jdbcType=VARCHAR} 
           , RVISN_DTTM = SYSDATE
           , DEPT = #{dept, jdbcType=VARCHAR} 
           , IP_INFO = #{ipInfo, jdbcType=VARCHAR} 
           , MAC_ADDR = #{macAddr, jdbcType=VARCHAR} 

           , USG_STRT_DT = #{usgStrtDt, jdbcType=VARCHAR} 
           , USG_END_DT = #{usgEndDt, jdbcType=VARCHAR} 
           , PASS_LAST_RVISN_DT = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
           , MNGR_RULE = #{mngrRule, jdbcType=VARCHAR} 
           , MSK_AUTH_YN = DECODE(#{mskAuthYn},'0','N','1','Y',#{mskAuthYn}) 
           , ORGN_ID = #{orgnId, jdbcType=VARCHAR} 
           , KOS_ID = #{kosId, jdbcType=VARCHAR} 
           , MAC_CHK_YN = #{macChkYn, jdbcType=VARCHAR} 
      WHERE USR_ID = #{usrId}

	   UPDATE CMN_USR_MST /** UserInfoMgmtMapper.updateUserInfoMgmtMsk */ 
           SET
            ATTC_SCTN_CD = #{attcSctnCd, jdbcType=VARCHAR} 
           , PASS = #{pass, jdbcType=VARCHAR} 
           , PRES_BIZ = #{presBiz, jdbcType=VARCHAR} 
           , POS = #{pos, jdbcType=VARCHAR} 
           , ODTY = #{odty, jdbcType=VARCHAR} 
           , RVISN_ID = #{rvisnId, jdbcType=VARCHAR} 
           , RVISN_DTTM = SYSDATE
           , DEPT = #{dept, jdbcType=VARCHAR} 
           , IP_INFO = #{ipInfo, jdbcType=VARCHAR} 
           , MAC_ADDR = #{macAddr, jdbcType=VARCHAR} 

           , USG_STRT_DT = #{usgStrtDt, jdbcType=VARCHAR} 
           , USG_END_DT = #{usgEndDt, jdbcType=VARCHAR} 
           , PASS_LAST_RVISN_DT = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
           , MNGR_RULE = #{mngrRule, jdbcType=VARCHAR} 
           , MSK_AUTH_YN = #{mskAuthYn, jdbcType=VARCHAR} 
           , ORGN_ID = #{orgnId, jdbcType=VARCHAR} 
           , MAC_CHK_YN = #{macChkYn, jdbcType=VARCHAR} 
      WHERE USR_ID = #{usrId}

		UPDATE CMN_USR_MST /** UserInfoMgmtMapper.deleteUserInfoMgmt */
           SET USG_YN = 'N'
               , DEL_RSN = #{delRsn}
               , MSK_AUTH_YN = 'N'
               , MNGR_RULE = 'N'
               , KOS_ID = null

           	   , RVISN_ID = #{rvisnId, jdbcType=VARCHAR} 

           	   , RVISN_DTTM = SYSDATE
		 WHERE USR_ID = #{usrId}

    	/* UserInfoMgmtMapper.deleteUserInfoMgmtCanAsgn */
		UPDATE CMN_USR_MST@DL_CAN 
			SET USG_YN = 'N' 
               , MSK_AUTH_YN = 'N'
               , USG_END_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
		WHERE USR_ID = #{usrId}

UPDATE CMN_USR_MST /** UserInfoMgmtMapper.initUserPassword */
   SET PASS = #{pass}
       , PASS_ERR_NUM = 0
       , PASS_INIT = 'Y' 
       , PASS_LAST_RVISN_DT = #{passLastRvisnDt}

       , RVISN_ID = #{rvisnId, jdbcType=VARCHAR} 

       , RVISN_DTTM = SYSDATE
 WHERE USR_ID = #{usrId}

