SELECT /** UserInfoMgmtMapper.selectUserHst */ USR_ID /* 사용자 ID */ , SEQ_NUM /* 사용자이력일련번호 */ , ATTC_SCTN_CD /* 소속 구분 코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = USR.ATTC_SCTN_CD) as ATTC_SCTN_CD_NM , USR_NM /* 사용자 명 */ --, PASS /* 비밀번호 */ , TEL_NUM /* 전화 번호 */ , MBLPHN_NUM /* 핸드폰 번호 */ , LAST_LOGIN_DT /* 최종 로그인 일시 */ , PASS_ERR_NUM /* 암호 오류 횟수 */ , PRES_BIZ /* 사번 */ , EMAIL /* 이메일 */ , POS /* 직위 */ , ODTY /* 직책 */ , ADDR /* 주소 */ , DTL_ADDR /* 주소2 */ , ZIPCD /* 우편 번호 */ , FAX /* FAX 번호 */ , PASS_ATMT_NUM /* 비밀번호 시도 횟수 */ , DEL_YN /* 삭제 여부 */ , REGST_ID /* 등록자 ID */ , TO_CHAR(REGST_DTTM,'YYYY-MM-DD HH:mm:ss') as REGST_DTTM /* 등록 일시 */ , RVISN_ID /* 수정자 ID */ , FN_GET_USRNM(RVISN_ID) AS RVISN_NM /* 수정자 */ , TO_CHAR(RVISN_DTTM,'YYYY-MM-DD HH:mm:ss') as RVISN_DTTM /* 수정일시 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = USR.DEPT) as DEPT_NM , DEPT /* 부서코드 */ , IP_INFO /* IP정보 */ , MAC_ADDR /* MAC주소 */ , USG_YN /* 사용여부 */ , USG_STRT_DT /* 사용시작일자 */ , USG_END_DT /* 사용종료일자 */ , PASS_LAST_RVISN_DT /* 최종비밀번호변경일시 */ , DECODE(MNGR_RULE, 'Y', 'Y', '1', 'Y', 'N') AS MNGR_RULE /* 관리자룰 */ , DECODE(MSK_AUTH_YN, 'Y', 'Y', '1', 'Y', 'N') AS MSK_AUTH_YN /* 마스킹권한여부 */ , ORGN_ID /*조직ID*/ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = USR.ORGN_ID AND ROWNUM = 1) as ORGN_NM , DEL_RSN FROM CMN_USR_HST USR WHERE 1=1 AND ATTC_SCTN_CD != '30'
AND USR_ID LIKE UPPER(#{usrId}||'%')
AND USR_NM LIKE '%'|| #{usrNm}||'%'
AND USG_YN = #{usgYn}
AND ATTC_SCTN_CD = #{attcSctnCd}
AND DEPT = #{dept}
AND ORGN_ID = #{orgnId}
ORDER BY TO_NUMBER(SEQ_NUM) DESC

	SELECT /* UserInfoMgmtMapper.isOldPass */
           COUNT(*) 
      FROM CMN_USR_MST 
     WHERE USR_ID = #{usrId}
       AND PASS = #{oldPass}

/* UserInfoMgmtMapper.selectShopUserInfoMgmtList */ SELECT ORGN_ID , ORGN_NM , USR_ID , USR_ID_MSK , USR_NM , MBLPHN_NUM , LAST_LOGIN_DT , USG_YN , USG_NM , PASS_INIT , M2M_YN FROM ( SELECT CUM.ORGN_ID , ORG.ORGN_NM , CUM.USR_ID AS USR_ID , CUM.USR_ID AS USR_ID_MSK , CUM.USR_NM AS USR_NM , CUM.MBLPHN_NUM AS MBLPHN_NUM , TO_CHAR(CUM.LAST_LOGIN_DT, 'YYYY-MM-DD HH24:MI:SS') AS LAST_LOGIN_DT
, CASE WHEN CUPR.STATUS = 'E' AND CUM.LOCK_YN = 'Y' THEN 'A' WHEN CUPR.STATUS = 'E' THEN 'E' WHEN CUM.LOCK_YN = 'Y' THEN 'L' ELSE CUM.USG_YN END AS USG_YN , CASE WHEN CUPR.STATUS='E' OR CUM.LOCK_YN = 'Y' THEN FN_GET_CODENM('CMN0100', 'E') ELSE FN_GET_CODENM('CMN0100', CUM.USG_YN ) END AS USG_NM , CUM.PASS_INIT AS PASS_INIT , CUM.M2M_YN , CUM.REGST_DTTM FROM CMN_USR_MST CUM , (SELECT DISTINCT ORGN_ID, ORGN_NM, TYPE_CD FROM ORG_ORGN_INFO_MST) ORG , (SELECT USR_ID , STATUS FROM ( SELECT ROW_NUMBER() OVER (PARTITION BY USR_ID ORDER BY REG_DTTM DESC,RVISN_DTTM) AS RNK , USR_ID , STATUS , REG_DTTM FROM CMN_USR_PWD_RESET CUPR )X WHERE X.RNK = 1 ) CUPR WHERE CUM.ORGN_ID = ORG.ORGN_ID AND CUM.USR_ID = CUPR.USR_ID(+) AND CUM.USG_YN != 'N' AND CUM.ATTC_SCTN_CD = '30' AND ORG.TYPE_CD = '30'
AND CUM.USR_ID LIKE UPPER(#{usrId}||'%')
AND CUM.USR_NM LIKE '%'|| #{usrNm} ||'%'
AND CUM.ORGN_ID = #{orgnId}
AND (CUM.M2M_YN = 'Y' OR ORG.ORGN_ID IN (SELECT DISTINCT ORGN_ID FROM CMN_USG_GRP_ASGN_MST A, CMN_USR_MST B WHERE A.USR_ID = B.USR_ID AND A.GRP_ID = 'G-PSCM2M' AND B.USG_YN <> 'N'))
)X WHERE 1=1
AND X.USG_YN = #{usgYn}
ORDER BY X.REGST_DTTM DESC

