UPDATE CMN_USR_STOP_MST
   SET STOP_YN = 'N'
       , PROC_ID = #{sessionUserId}
       , PROC_DT = TO_CHAR(SYSDATE, 'YYYYMMDD')
       , RVISN_ID = #{sessionUserId}
       , RVISN_DTTM = SYSDATE
 WHERE USR_ID = #{usrId}
   AND STOP_YN = 'Y'

mapper.select:
/* UserStopStatusMapper.getUserStopStatusList */ SELECT A.USR_ID ,A.USR_ID AS USR_ID_MSK ,B.USR_NM ,A.STOP_DT ,A.STOP_YN ,FN_GET_CODENM('CMN0101', A.STOP_YN) AS STOP_CD_NAME ,A.PROC_ID ,FN_GET_USRNM(A.PROC_ID) AS PROC_NM ,A.PROC_DT ,B.ATTC_SCTN_CD ,FN_GET_CODENM('CMN0003', B.ATTC_SCTN_CD) AS ATTC_SCTN_NM ,B.LAST_LOGIN_DT ,B.ORGN_ID ,FN_GET_ORGNM(B.ORGN_ID) AS ORGN_NM ,B.MBLPHN_NUM ,B.EMAIL FROM CMN_USR_STOP_MST A ,CMN_USR_MST B WHERE A.USR_ID = B.USR_ID AND B.ATTC_SCTN_CD != '30'
AND B.USG_YN != 'N'
AND A.USR_ID = #{usrId}
AND B.USR_NM LIKE '%' || #{usrNm} || '%'
AND B.ORGN_ID = #{orgnId}
AND B.ATTC_SCTN_CD = #{orgType}
AND A.STOP_YN = #{stopYn}
ORDER BY A.STOP_DT DESC, B.USR_NM

