UPDATE CMN_USR_STOP_MST
SET    STOP_YN = #{stopYn, jdbcType=VARCHAR}
     , PROC_ID = #{procId, jdbcType=VARCHAR}
     , PROC_DT = TO_CHAR(SYSDATE, 'YYYYMMDD')
     , RVISN_ID = #{rvisnId, jdbcType=VARCHAR}
     , RVISN_DTTM = SYSDATE
WHERE  USR_ID = #{usrId, jdbcType=VARCHAR}
AND    STOP_DT = #{stopDt, jdbcType=VARCHAR}

UPDATE CMN_USR_MST
SET    USG_YN = #{usgYn, jdbcType=VARCHAR}
      ,RVISN_ID = #{rvisnId, jdbcType=VARCHAR} 
      ,RVISN_DTTM = SYSDATE
      ,LAST_LOGIN_DT = SYSDATE
WHERE  USR_ID = #{usrId, jdbcType=VARCHAR}

mapper.select:
/* UserStopStatusMapper.getUserStopStatusList */ SELECT A.USR_ID as usrId ,B.USR_NM as usrNm ,A.STOP_DT as stopDt ,A.STOP_YN as stopYn ,FN_GET_CODENM('CMN0101', A.STOP_YN) AS stopCdName ,A.PROC_ID as procId ,FN_GET_USRNM(A.PROC_ID) AS procNm ,A.PROC_DT as procDt ,B.ATTC_SCTN_CD as attcSctnCd ,FN_GET_CODENM('CMN0003', B.ATTC_SCTN_CD) AS attcSctnNm ,B.LAST_LOGIN_DT as lastLoginDt ,B.ORGN_ID as orgnId ,FN_GET_ORGNM(B.ORGN_ID) AS orgnNm ,B.MBLPHN_NUM as mblphnNum ,B.EMAIL as email FROM CMN_USR_STOP_MST A ,CMN_USR_MST B WHERE A.USR_ID = B.USR_ID AND B.ATTC_SCTN_CD != '30'
AND B.USG_YN != 'N'
AND A.USR_ID = #{usrId}
AND B.USR_NM LIKE '%' || #{usrNm} || '%'
AND B.ORGN_ID = #{orgnId}
AND B.ATTC_SCTN_CD = #{orgType}
AND A.STOP_YN = #{stopYn}
ORDER BY A.STOP_DT DESC, B.USR_NM

SELECT /* UserInfoMgmtMapper.selectuserMacAddressMgmtList */ MST.TYPE_CD AS ORG_TYPE ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = MST.TYPE_CD) AS ORG_TYPE_NM ,MST.ORGN_NM AS ORGN_NM ,CUM.USR_NM AS USR_NM ,CUM.USR_ID AS USR_ID ,CUM.USR_ID AS USR_ID_MSK ,MAC.MAC_ADDRESS AS MAC_ADDR ,MAC.MAC_NAME AS MAC_NM ,MAC.MAC_DESCRIPTION AS MAC_DESC FROM ORG_ORGN_INFO_MST MST ,CMN_USR_MST CUM ,EMV_SCAN_USER_INFO MAC WHERE MST.ORGN_ID = CUM.ORGN_ID AND CUM.USR_ID = MAC.RGST_PRSN_ID AND CUM.USG_YN = 'Y'
AND CUM.USR_ID LIKE '%' || UPPER(#{usrId}) || '%'
AND CUM.USR_NM LIKE '%' || #{usrNm} || '%'
AND MST.TYPE_CD = #{orgType}
AND CUM.ORGN_ID = #{orgnId}
ORDER BY CUM.USR_NM

mapper.insert:
