mapper.select:
SELECT /* UserInfoMgmtMapper.selectSalesUserInfoMgmtList */ CUM.USR_ID /* 사용자 ID */ , ORG.TYPE_CD AS ORG_TYPE /* 소속 구분 코드 */ , FN_GET_CODENM('CMN0115',ORG.TYPE_CD) AS ORG_TYPE_NM , CUM.USR_NM /* 사용자 명 */ , CUM.MBLPHN_NUM /* 핸드폰 번호 */ , TO_CHAR(CUM.LAST_LOGIN_DT,'YYYY-MM-DD HH:mm:ss') AS LAST_LOGIN_DT /* 최종 로그인 일시 */ , CUM.RVISN_ID /* 수정자 ID */ , CASE WHEN CUM.RVISN_ID = 'SYSTEM' THEN 'SYSTEM' ELSE FN_GET_USRNM(CUM.RVISN_ID) END AS RVISN_NM /* 수정자 */ , TO_CHAR(CUM.RVISN_DTTM,'YYYY-MM-DD HH:mm:ss') AS RVISN_DTTM /* 수정일시 */ , FN_GET_CODENM('CMN0100',CUM.USG_YN) AS USG_YN /* 사용여부 */ , CUM.ORGN_ID , ORG.ORGN_NM , CUM.REGST_ID , CASE WHEN CUM.REGST_ID = 'SYSTEM' THEN 'SYSTEM' ELSE FN_GET_USRNM(CUM.REGST_ID) END AS REGST_NM /* 등록자 */ , TO_CHAR(CUM.REGST_DTTM,'YYYY-MM-DD HH:mm:ss') AS REGST_DTTM /* 등록일시 */ FROM CMN_USR_MST CUM ,(SELECT DISTINCT ORGN_ID, ORGN_NM, DECODE(ORGN_ID, 'A30040999', '15', TYPE_CD) TYPE_CD FROM ORG_ORGN_INFO_MST) ORG WHERE CUM.ORGN_ID = ORG.ORGN_ID AND ORG.TYPE_CD != '10' AND CUM.USG_YN != 'N'
AND CUM.USR_ID LIKE UPPER('%'||#{usrId}||'%')
AND CUM.USR_NM LIKE '%'|| UPPER(#{usrNm}) ||'%'
AND CUM.USG_YN = #{usgYn}
AND ORG.TYPE_CD = #{orgType}
AND CUM.ORGN_ID = #{orgnId}
ORDER BY REGST_DTTM DESC

SELECT /* UserInfoMgmtMapper.getSalesUserInfoMgmtListExcel */ CUM.USR_ID AS usrId /* 사용자 ID */ , ORG.TYPE_CD AS ORG_TYPE /* 소속 구분 코드 */ , FN_GET_CODENM('CMN0115',ORG.TYPE_CD) AS orgTypeNm , CUM.USR_NM AS usrNm /* 사용자 명 */ , CUM.MBLPHN_NUM AS mblphnNum /* 핸드폰 번호 */ , TO_CHAR(CUM.LAST_LOGIN_DT,'YYYY-MM-DD HH:mm:ss') AS lastLoginDt /* 최종 로그인 일시 */ , CUM.RVISN_ID /* 수정자 ID */ , CASE WHEN CUM.RVISN_ID = 'SYSTEM' THEN 'SYSTEM' ELSE FN_GET_USRNM(CUM.RVISN_ID) END AS rvisnNm /* 수정자 */ , TO_CHAR(CUM.RVISN_DTTM,'YYYY-MM-DD HH:mm:ss') AS rvisnDttm /* 수정일시 */ , FN_GET_CODENM('CMN0100',CUM.USG_YN) AS usgYn /* 사용여부 */ , CUM.ORGN_ID , ORG.ORGN_NM AS orgnNm , CUM.REGST_ID , CASE WHEN CUM.REGST_ID = 'SYSTEM' THEN 'SYSTEM' ELSE FN_GET_USRNM(CUM.REGST_ID) END AS regstNm /* 등록자 */ , TO_CHAR(CUM.REGST_DTTM,'YYYY-MM-DD HH:mm:ss') AS regstDttm /* 등록일시 */ FROM CMN_USR_MST CUM ,(SELECT DISTINCT ORGN_ID, ORGN_NM, DECODE(ORGN_ID, 'A30040999', '15', TYPE_CD) TYPE_CD FROM ORG_ORGN_INFO_MST) ORG WHERE CUM.ORGN_ID = ORG.ORGN_ID AND ORG.TYPE_CD != '10' AND CUM.USG_YN != 'N'
AND CUM.USR_ID LIKE UPPER('%'||#{usrId}||'%')
AND CUM.USR_NM LIKE '%'|| UPPER(#{usrNm}) ||'%'
AND CUM.USG_YN = #{usgYn}
AND ORG.TYPE_CD = #{orgType}
AND CUM.ORGN_ID = #{orgnId}
ORDER BY REGST_DTTM DESC

SELECT A.USR_ID /* 사용자 ID */ , A.USR_ID AS USR_ID_MSK /* 사용자 ID */ , A.SEQ_NUM /* 사용자이력일련번호 */ , A.ATTC_SCTN_CD /* 소속 구분 코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = A.ATTC_SCTN_CD) AS ATTC_SCTN_CD_NM , A.USR_NM /* 사용자 명 */ , A.MBLPHN_NUM /* 핸드폰 번호 */ , A.FAX /* FAX 번호 */ , A.USG_STRT_DT /* 사용시작일자 */ , A.USG_END_DT /* 사용종료일자 */ , A.ORGN_ID /* 조직ID */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = A.ORGN_ID AND ROWNUM = 1) AS ORGN_NM , TO_CHAR(A.APL_DT, 'YYYY-MM-DD HH24:MI:SS') AS APL_DT /* 신청일자 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0256' AND CD_VAL = A.APP_YN) AS APP_YN /* 승인여부 A:승인완료 , C:반려 , P:신청중, D:처리완료*/ , A.APP_FILE_ID1 /* 신청파일1 */ , A.APP_FILE_ID2 /* 신청파일2 */ , A.APP_USR_ID /* 승인자ID */ , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = A.APP_USR_ID) AS APP_USR_NM , TO_CHAR(A.APP_DT, 'YYYY-MM-DD HH24:MI:SS') AS APP_DT /* 승인일자 */ , A.REF_RSN /* 반려사유 */ , DECODE((SELECT COUNT(*) FROM CMN_USR_MST WHERE USR_ID = A.USR_ID AND APP_YN = 'P'),1,'Y','N') AS MOD_CHK /* 승인데이터 확인 */ FROM CMN_USR_HST A , ( SELECT USR_ID, MAX(SEQ_NUM) AS SEQ_NUM FROM CMN_USR_HST WHERE APL_DT IS NOT NULL GROUP BY USR_ID ) B WHERE A.USR_ID = B.USR_ID AND A.SEQ_NUM = B.SEQ_NUM AND A.APP_USR_ID = #{appUsrId}
AND A.USR_ID LIKE UPPER(#{usrId}||'%')
AND A.USR_NM LIKE '%'|| UPPER(#{usrNm}) ||'%'
AND A.ORGN_ID = #{orgnId}
AND A.APP_YN = #{appYn}
AND A.APL_DT BETWEEN TO_DATE(#{searchStartDt, jdbcType=VARCHAR} || '000000','YYYYMMDDHH24MISS' ) AND TO_DATE(#{searchEndDt, jdbcType=VARCHAR} || '235959','YYYYMMDDHH24MISS' )
ORDER BY APL_DT DESC

SELECT COUNT(*) 
  FROM CMN_USR_HST 
 WHERE USR_ID = #{usrId}
   AND SEQ_NUM = #{seqNum}
   AND APP_YN = 'P'

