/* ====== cmn.login.insertSearchLog =========*/
INSERT INTO CMN_CUS_SEARCH_LOG_MST
    (USR_ID

    	,CONTRACT_NUM


    	,RES_NO



    	,SELF_DLVRY_IDX

    ,CONN_DT
    ,MENU_NM
    ,TAB_ID
    ,TAB_NM

    	,IP_INFO

    )
SELECT
    #{SESSION_USER_ID}

    	,#{contractNum}


    	,(SELECT RES_NO FROM MCP_REQUEST@DL_MCP WHERE REQUEST_KEY = #{requestKey})


    	,#{resNo}


    	,#{selFDlvryIdx}

    ,SYSDATE
    ,(SELECT MENU_NM FROM CMN_MENU_MST WHERE MENU_ID = #{trgtMenuId})
    ,#{tabId}
    ,DECODE(#{tabId},'a1','가입자정보','a4','계약이력','a7','납부방법','a9','법정대리인','paper','서식지보기','')

    	,#{ipInfo}

FROM DUAL
WHERE NOT EXISTS (SELECT 1 FROM CMN_CUS_SEARCH_LOG_MST
				WHERE 	USR_ID = #{SESSION_USER_ID}
				AND		MENU_NM = (SELECT MENU_NM FROM CMN_MENU_MST WHERE MENU_ID = #{trgtMenuId})

					AND		CONTRACT_NUM = #{contractNum}


					AND		RES_NO = (SELECT RES_NO FROM MCP_REQUEST@DL_MCP WHERE REQUEST_KEY = #{requestKey})


			    	AND		RES_NO = #{resNo}


					AND		TAB_ID = #{tabId}

				AND		((CONN_DT = SYSDATE - 0.00001) OR (CONN_DT = SYSDATE)))

