/* UserInfoMgmtMapper.getUserPwdResetList */ SELECT A.USR_ID ,A.USR_ID AS USR_ID_MSK ,B.USR_NM ,TO_CHAR(A.REG_DTTM,'YYYY-MM-DD') AS APL_DT ,DECODE(A.STATUS,'Y','Y','C','C','N') AS STATUS ,FN_GET_CODENM('CMN0114',DECODE(A.STATUS,'Y','Y','C','C','N')) AS STATUS_NM ,A.PROC_ID ,FN_GET_USRNM(A.PROC_ID) AS PROC_NM ,A.PROC_DT ,B.ATTC_SCTN_CD ,FN_GET_CODENM('CMN0003', B.ATTC_SCTN_CD) AS ATTC_SCTN_NM ,B.LAST_LOGIN_DT ,B.ORGN_ID ,FN_GET_ORGNM(B.ORGN_ID) AS ORGN_NM ,B.MBLPHN_NUM ,B.EMAIL FROM CMN_USR_PWD_RESET A ,CMN_USR_MST B WHERE A.USR_ID = B.USR_ID AND B.ATTC_SCTN_CD != '30'
AND A.USR_ID LIKE UPPER(#{usrId}||'%')
AND B.USR_NM LIKE '%' || #{usrNm} || '%'
AND B.ORGN_ID = #{orgnId}
AND B.ATTC_SCTN_CD = #{orgType}
AND DECODE(A.STATUS,'Y','Y','C','C','N') = #{status}
ORDER BY A.REG_DTTM DESC, B.USR_NM

