/* UserInfoMgmtMapper.updateUserPwdReset */
	UPDATE CMN_USR_PWD_RESET
	SET
		PROC_ID = #{procId}
		,PROC_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
		,RVISN_ID = #{rvisnId}
		,RVISN_DTTM = SYSDATE
		,STATUS = #{status}
	WHERE USR_ID = #{usrId}
	AND STATUS NOT IN ('Y','C')

