/* UserInfoMgmtMapper.getUserLockResetList */ SELECT A.USR_ID ,A.USR_ID AS USR_ID_MSK ,A.USR_NM ,A.ATTC_SCTN_CD ,FN_GET_CODENM('CMN0003', A.ATTC_SCTN_CD) AS ATTC_SCTN_NM ,A.LAST_LOGIN_DT ,A.ORGN_ID ,FN_GET_ORGNM(A.ORGN_ID) AS ORGN_NM ,A.MBLPHN_NUM ,A.EMAIL ,A.LOCK_YN FROM CMN_USR_MST A WHERE A.LOCK_YN = 'Y' AND A.USG_YN = 'Y' AND A.ATTC_SCTN_CD != '30'
